import torch
from torch.utils.checkpoint import checkpoint

# Gradient checkpointing: recompute activations in backward pass
# Reduces peak activation memory for long chains of layers

class LargeLayer(torch.nn.Module):
    def __init__(self):
        super().__init__()
        self.layers = torch.nn.Sequential(
            *[torch.nn.Linear(512, 512) for _ in range(8)]
        )

    def forward(self, x):
        # Use checkpoint to avoid storing all intermediate activations
        return checkpoint(self.layers, x, use_reentrant=False)

# Memory comparison for 100M parameter model:
# Without checkpointing: ~8 GB for activations alone
# With checkpointing:    ~2 GB (recomputes forward on backward)
